class Solution:
    def findLUSlength(self, strs: List[str]) -> int:
        def subseq(a, b):
            i = 0
            for c in b:
                if i < len(a) and a[i] == c:
                    i += 1
            return i == len(a)
        strs.sort(key=len, reverse=True)
        for i, s in enumerate(strs):
            if all(i == j or not subseq(s, strs[j]) for j in range(len(strs))):
                return len(s)
        return -1

